import{_ as a,c as o,o as r,R as e}from"./chunks/framework.Dxoqk0BT.js";const p=JSON.parse('{"title":"前端架构指南","description":"","frontmatter":{},"headers":[],"relativePath":"think/1.md","filePath":"think/1.md"}'),l={name:"think/1.md"};function i(n,t,s,h,d,u){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="前端架构指南" tabindex="-1">前端架构指南 <a class="header-anchor" href="#前端架构指南" aria-label="Permalink to &quot;前端架构指南&quot;">​</a></h1><h2 id="前端的核心价值" tabindex="-1">前端的核心价值 <a class="header-anchor" href="#前端的核心价值" aria-label="Permalink to &quot;前端的核心价值&quot;">​</a></h2><p>前端 = 人机交互工程师</p><p>前端的核心价值，是完成技术的最后一公里，让技术可交付给用户使用，是科技触达用户的桥梁，是数字世界里的建筑师。</p><h2 id="什么是前端架构" tabindex="-1">什么是前端架构？ <a class="header-anchor" href="#什么是前端架构" aria-label="Permalink to &quot;什么是前端架构？&quot;">​</a></h2><p>前端架构是根据业务需求驱动，通过权衡利弊并考量现实约束后，做出的塑造系统全局特性且难以逆转的高层次技术决策。</p><p>本质是：以业务目标为锚点，通过有意识的全局技术决策，赋予系统关键属性（如灵活性、容错性），并为之承担代价的过程。</p><h2 id="架构的关键特征" tabindex="-1">架构的关键特征 <a class="header-anchor" href="#架构的关键特征" aria-label="Permalink to &quot;架构的关键特征&quot;">​</a></h2><blockquote><p>存在问题：前端社区过度关注工具（框架、库等）而非系统本质，导致决策缺乏深度和长期价值。</p></blockquote><ol><li><strong>业务驱动</strong>：业务需求（如响应速度、团队规模、容错要求）是决策的出发点，由业务目标（如交付速度、稳定性需求）定义系统特性。</li><li><strong>权衡取舍</strong>：任何技术选择都有代价（如重用性提升可能牺牲团队独立性），需要在约束下平衡长期目标与短期交付。</li><li><strong>约束条件</strong>：现实限制（如资源、时间、遗留系统）影响决策可行性。</li><li><strong>决策导向</strong>：关注&quot;做什么&quot;（如状态集中化、模块边界划分）而非&quot;如何做&quot;（工具选型），做出高层次的、影响系统全局特性的选择（如微前端策略、状态管理模式）。</li><li><strong>全局性影响</strong>：决策影响系统整体属性（如灵活性、可维护性、容错能力）。</li><li><strong>不可逆性</strong>：决策代价高昂，需长期承担（如选择微前端后重构成本极高）。</li></ol><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>❌ <strong>架构 ≠ 目录结构/工具库</strong>：目录结构、工具库（Redux 等）、编码规范属于实现细节，是架构的实现手段而非本质</li><li>❌ <strong>架构 ≠ 复制他人方案</strong>：架构需适配具体业务场景，无通用&quot;银弹&quot;，不能盲目复制&quot;最佳实践&quot;</li><li>❌ <strong>架构 ≠ 技术选型</strong>：技术选型是战术层面的实现细节，架构决策是战略层面的高层次选择</li></ul><h2 id="架构师的核心职责" tabindex="-1">架构师的核心职责 <a class="header-anchor" href="#架构师的核心职责" aria-label="Permalink to &quot;架构师的核心职责&quot;">​</a></h2><p>在业务目标、技术可行性及团队能力间找到平衡点，通过沟通业务、技术、团队等多方需求，分析权衡，确保系统具备支撑长期成功的属性（如弹性、可演进性），而非追求技术潮流或形式规范。</p>',14)])])}const q=a(l,[["render",i]]);export{p as __pageData,q as default};
